1	/*
2	* @info Vector Store Unit
3	*
4	* @author VLSI Lab, EE dept., Democritus University of Thrace
5	*
6	*/
7	`ifdef MODEL_TECH
8	    `include "vstructs.sv"
9	`endif
10	module vmu_st_eng #(
11	    parameter int REQ_DATA_WIDTH     = 256,
12	    parameter int VECTOR_REGISTERS   = 32 ,
13	    parameter int VECTOR_LANES       = 8  ,
14	    parameter int DATA_WIDTH         = 32 ,
15	    parameter int ADDR_WIDTH         = 32 ,
16	    parameter int MICROOP_WIDTH      = 5  ,
17	    parameter int VECTOR_TICKET_BITS = 4
18	) (
19	    input  logic                                clk                ,
20	    input  logic                                rst_n              ,
21	    //Input Interface
22	    input  logic                                valid_in           ,
23	    input  memory_remapped_v_instr              instr_in           ,
24	    output logic                                ready_o            ,
25	    //RF Interface (per vreg)
26	    output logic [$clog2(VECTOR_REGISTERS)-1:0] rd_addr_1_o        ,
27	    input  logic [ VECTOR_LANES*DATA_WIDTH-1:0] rd_data_1_i        ,
28	    input  logic                                rd_pending_1_i     ,
29	    input  logic [      VECTOR_TICKET_BITS-1:0] rd_ticket_1_i      ,
30	    //RF Interface (for `OP_INDEXED stride)
31	    output logic [$clog2(VECTOR_REGISTERS)-1:0] rd_addr_2_o        ,
32	    input  logic [ VECTOR_LANES*DATA_WIDTH-1:0] rd_data_2_i        ,
33	    input  logic                                rd_pending_2_i     ,
34	    input  logic [      VECTOR_TICKET_BITS-1:0] rd_ticket_2_i      ,
35	    //Unlock Interface
36	    output logic                                unlock_en_o        ,
37	    output logic [$clog2(VECTOR_REGISTERS)-1:0] unlock_reg_a_o     ,
38	    output logic [$clog2(VECTOR_REGISTERS)-1:0] unlock_reg_b_o     ,
39	    output logic [      VECTOR_TICKET_BITS-1:0] unlock_ticket_o    ,
40	    //Request Interface
41	    input  logic                                grant_i            ,
42	    output logic                                req_en_o           ,
43	    output logic [              ADDR_WIDTH-1:0] req_addr_o         ,
44	    output logic [           MICROOP_WIDTH-1:0] req_microop_o      ,
45	    output logic [  $clog2(REQ_DATA_WIDTH/8):0] req_size_o         ,
46	    output logic [          REQ_DATA_WIDTH-1:0] req_data_o         ,
47	    //Sync Interface
48	    output logic                                is_busy_o          ,
49	    output logic                                can_be_inteleaved_o,
50	    output logic [              ADDR_WIDTH-1:0] start_addr_o       ,
51	    output logic [              ADDR_WIDTH-1:0] end_addr_o
52	);
53	
54	    localparam int ELEMENT_ADDR_WIDTH   = $clog2(VECTOR_LANES)                                                       ;
55	    localparam int VREG_ADDR_WIDTH      = $clog2(VECTOR_REGISTERS)                                                   ;
56	    localparam int MAX_MEM_SERVED_LIMIT = REQ_DATA_WIDTH / DATA_WIDTH                                                ;
57	    localparam int MAX_RF_SERVED_COUNT  = VECTOR_REGISTERS                                                           ;
58	    localparam int MAX_SERVED_COUNT     = (VECTOR_LANES > MAX_MEM_SERVED_LIMIT) ? MAX_MEM_SERVED_LIMIT : VECTOR_LANES;
59	
60	    //=======================================================
61	    // REGISTERS
62	    //=======================================================
63	    logic [                       VECTOR_LANES-1:0] pending_elem        ;
64	    logic [                      MICROOP_WIDTH-1:0] microop_r           ;
65	    logic [                 VECTOR_TICKET_BITS-1:0] ticket_r            ;
66	    logic [                    VREG_ADDR_WIDTH-1:0] src1_r              ;
67	    logic [                    VREG_ADDR_WIDTH-1:0] src2_r              ;
68	    logic [                    VREG_ADDR_WIDTH-1:0] rdst_r              ;
69	    logic [                 VECTOR_TICKET_BITS-1:0] last_ticket_src1_r  ;
70	    logic [                 VECTOR_TICKET_BITS-1:0] last_ticket_src2_r  ;
71	    logic [$clog2(VECTOR_REGISTERS*VECTOR_LANES):0] instr_vl_r          ;
72	    logic [                    VREG_ADDR_WIDTH-1:0] current_exp_loop_r  ;
73	    logic [                    VREG_ADDR_WIDTH-1:0] max_expansion_r     ;
74	    logic [                   ELEMENT_ADDR_WIDTH:0] current_pointer_wb_r;
75	    logic [                         ADDR_WIDTH-1:0] current_addr_r      ;
76	    logic [                         ADDR_WIDTH-1:0] base_addr_r         ;
77	    logic [                         ADDR_WIDTH-1:0] stride_r            ;
78	    logic [                                    1:0] size_r              ;
79	    logic [                                    1:0] memory_op_r         ;
80	    logic [                         ADDR_WIDTH-1:0] start_addr_r        ;
81	    logic [                         ADDR_WIDTH-1:0] end_addr_r          ;
82	    //=======================================================
83	    // WIRES
84	    //=======================================================
85	    logic [                     REQ_DATA_WIDTH-1:0] data_selected               ;
86	    logic [$clog2(VECTOR_REGISTERS*VECTOR_LANES):0] total_remaining_elements    ;
87	    logic [$clog2(VECTOR_REGISTERS*VECTOR_LANES):0] nxt_total_remaining_elements;
88	    logic [                 $clog2(VECTOR_LANES):0] loop_remaining_elements     ;
89	    logic [    $clog2(VECTOR_LANES*DATA_WIDTH)-1:0] element_index               ;
90	    logic [                     REQ_DATA_WIDTH-1:0] data_selected_v             ;
91	    logic [                         DATA_WIDTH-1:0] data_selected_el            ;
92	    logic [                 ELEMENT_ADDR_WIDTH-1:0] nxt_elem                    ;
93	    logic [                   ELEMENT_ADDR_WIDTH:0] el_served_count             ;
94	    logic [                         VECTOR_LANES:0] current_pointer_oh          ;
95	    logic [                         VECTOR_LANES:0] current_served_th           ;
96	    logic [                         ADDR_WIDTH-1:0] nxt_base_addr               ;
97	    logic [                         ADDR_WIDTH-1:0] nxt_strided_addr            ;
98	    logic [                         ADDR_WIDTH-1:0] nxt_unit_strided_addr       ;
99	    logic [                         ADDR_WIDTH-1:0] current_addr                ;
100	    logic [                         ADDR_WIDTH-1:0] nxt_stride                  ;
101	    logic [                         ADDR_WIDTH-1:0] offset_read                 ;
102	    logic [                       VECTOR_LANES-1:0] nxt_pending_elem            ;
103	    logic [                       VECTOR_LANES-1:0] nxt_pending_elem_loop       ;
104	    logic [                                    1:0] nxt_memory_op               ;
105	    logic [                                    1:0] nxt_size                    ;
106	    logic                                           start_new_instruction       ;
107	    logic                                           maxvl_reached               ;
108	    logic                                           vl_reached                  ;
109	    logic                                           do_reconfigure              ;
110	    logic                                           current_finished            ;
111	    logic                                           currently_idle              ;
112	    logic                                           multi_valid                 ;
113	    logic                                           expansion_finished          ;
114	    logic                                           data_ready                  ;
115	    logic                                           addr_ready                  ;
116	    logic                                           start_new_loop              ;
117	    logic                                           new_transaction_en          ;
118	    logic                                           request_ready               ;
119	    // Create basic control flow
120	    //=======================================================
121	    assign ready_o             = currently_idle | current_finished;
122	    assign is_busy_o           = ~currently_idle;
123	    assign can_be_inteleaved_o = (memory_op_r !== `OP_INDEXED);
124	    //current instruction finished
125	    assign current_finished = expansion_finished & new_transaction_en & (~pending_elem[nxt_elem] | (loop_remaining_elements <= MAX_SERVED_COUNT));
126	    //currently no instructions are being served
127	    assign currently_idle = current_pointer_oh[0] & ~|pending_elem;
128	
129	    assign expansion_finished = maxvl_reached | vl_reached;
130	    assign maxvl_reached      = (current_exp_loop_r === (max_expansion_r-1));
131	    assign vl_reached         = (((current_exp_loop_r+1) << $clog2(VECTOR_LANES)) >= instr_vl_r);
132	
133	    assign start_new_instruction = valid_in & ready_o & ~instr_in.reconfigure;
134	    assign do_reconfigure        = valid_in & ready_o & instr_in.reconfigure;
135	
136	    // Start from element 0 on the next destination vreg
137	    assign start_new_loop = ~expansion_finished & new_transaction_en &
138	                            ((~current_pointer_oh[0] & ~pending_elem[nxt_elem]) |
139	                             (loop_remaining_elements >= MAX_SERVED_COUNT));
140	
141	    // Create the memory request control signals
142	    assign req_en_o      = request_ready;
143	    assign req_addr_o    = current_addr;
144	    assign req_data_o    = data_selected;
145	    assign req_microop_o = 5'b11111; //REVISIT will change based on instruction
146	    always_comb begin
147	        unique case (size_r)
148	            `SZ_8   : req_size_o = el_served_count;      //el_served_count * 1
149	            `SZ_16  : req_size_o = el_served_count << 1; //el_served_count * 2
150	            `SZ_32  : req_size_o = el_served_count << 2; //el_served_count * 4
151	            default : req_size_o = 'x;
152	        endcase
153	    end
154	
155	    assign new_transaction_en = request_ready & grant_i;
156	    assign request_ready      = data_ready & addr_ready & pending_elem[current_pointer_wb_r];
157	    assign data_ready         = ~rd_pending_1_i;
158	    assign addr_ready         = (memory_op_r === `OP_INDEXED) ? ~rd_pending_2_i & ((rd_ticket_2_i === ticket_r) | (rd_ticket_2_i === last_ticket_src2_r)) : 1'b1;
159	    // Unlock register signals
160	    assign unlock_en_o     = start_new_loop | current_finished;
161	    assign unlock_reg_a_o  = src1_r;
162	    assign unlock_reg_b_o  = src2_r;
163	    assign unlock_ticket_o = ticket_r;
164	
165	    // assign the rest of the outputs
166	    assign rd_addr_1_o  = src1_r;
167	    assign rd_addr_2_o  = src2_r;
168	    assign start_addr_o = start_addr_r;
169	    assign end_addr_o   = end_addr_r;
170	    //=======================================================
171	    // Address Generation
172	    //=======================================================
173	    assign multi_valid   = (memory_op_r === `OP_UNIT_STRIDED);
174	    assign element_index = current_pointer_wb_r << 5; //*32
175	    assign offset_read   = rd_data_2_i[element_index +: DATA_WIDTH];
176	    // Generate next non-multi consecutive address
177	    always_comb begin
178	        case (memory_op_r)
179	            `OP_UNIT_STRIDED : current_addr = current_addr_r;
180	            `OP_STRIDED      : current_addr = current_addr_r;
181	            `OP_INDEXED      : current_addr = base_addr_r + offset_read;
182	            default          : current_addr = 'X;
183	        endcase
184	    end
185	
186	    assign nxt_base_addr    = instr_in.data1 + instr_in.immediate;
187	    assign nxt_strided_addr = current_addr_r + stride_r;
188	    always_comb begin
189	        unique case (size_r)
190	            `SZ_8   : nxt_unit_strided_addr = current_addr_r + el_served_count;
191	            `SZ_16  : nxt_unit_strided_addr = current_addr_r + (el_served_count << 1);
192	            `SZ_32  : nxt_unit_strided_addr = current_addr_r + (el_served_count << 2);
193	            default : nxt_unit_strided_addr = 'X;
194	        endcase
195	    end
196	    //Hold current address
197	    always_ff @(posedge clk) begin
198	        if(start_new_instruction) begin
199	            current_addr_r <= nxt_base_addr;
200	        end else if (new_transaction_en && memory_op_r == `OP_STRIDED) begin
201	            current_addr_r <= nxt_strided_addr;
202	        end else if(new_transaction_en && memory_op_r == `OP_UNIT_STRIDED) begin
203	            current_addr_r <= nxt_unit_strided_addr;
204	        end
205	    end
206	    //Hold base address
207	    always_ff @(posedge clk) begin
208	        if(start_new_instruction) begin
209	            base_addr_r <= nxt_base_addr;
210	        end
211	    end
212	    //Hold stride
213	    assign nxt_stride = instr_in.data2;
214	    always_ff @(posedge clk) begin
215	        if(start_new_instruction) stride_r <= nxt_stride;
216	    end
217	    //Hold mem op size
218	    assign nxt_size = instr_in.microop[`MEM_SZ_RANGE_HI:`MEM_SZ_RANGE_LO];
219	    always_ff @(posedge clk) begin
220	        if(start_new_instruction) size_r <= nxt_size;
221	    end
222	    //=======================================================
223	    // Data Generation
224	    //=======================================================
225	    // single-element data to be stored
226	    assign data_selected_el = rd_data_1_i[element_index +: DATA_WIDTH];
227	    // vector of data to be stored
228	    assign data_selected_v = rd_data_1_i >> (current_pointer_wb_r << 5); //bring the data to bit0
229	
230	    // create the final data vector
231	    always_comb begin
232	        data_selected = '0;
233	        if(!multi_valid) begin
234	            data_selected[0+:32] = data_selected_el;
235	        end else begin
236	            for (int i = 0; i < MAX_SERVED_COUNT; i++) begin
237	                unique case (size_r)
238	                    `SZ_8   : data_selected[i*8 +: 8]   = data_selected_v[i*32 +:8];  //pick 8bits from each elem
239	                    `SZ_16  : data_selected[i*16 +: 16] = data_selected_v[i*32 +:16]; //pick 16bits from each elem
240	                    `SZ_32  : data_selected[i*32 +: 32] = data_selected_v[i*32 +:32]; //pick 32bits from each elem
241	                    default : data_selected[i*32 +: 32] = 'X;
242	                endcase
243	            end
244	        end
245	    end
246	
247	    //=======================================================
248	    // Scoreboard maintenance
249	    //=======================================================
250	    always_comb begin : proc_loop_remaining_el
251	        loop_remaining_elements = 0;
252	        for (int i = 0; i < VECTOR_LANES; i++) begin
253	            if (pending_elem[i]) loop_remaining_elements = loop_remaining_elements +1;
254	        end
255	    end
256	    assign total_remaining_elements     = instr_vl_r - (current_exp_loop_r*VECTOR_LANES);
257	    assign nxt_total_remaining_elements = instr_vl_r - ((current_exp_loop_r+1)*VECTOR_LANES);
258	    always_comb begin : get_served_el_cnt
259	        if (memory_op_r !== `OP_UNIT_STRIDED) begin
260	            el_served_count = 'd1;
261	        end else if (loop_remaining_elements < MAX_SERVED_COUNT) begin
262	            el_served_count = loop_remaining_elements; // remaining < max_width
263	        end else begin
264	            el_served_count = MAX_SERVED_COUNT; // remaining > max_width
265	        end
266	    end
267	    // Maintain current pointer
268	    assign nxt_elem = multi_valid ? (current_pointer_wb_r + el_served_count) : (current_pointer_wb_r +1);
269	    always_ff @(posedge clk or negedge rst_n) begin : current_ptr
270	        if(~rst_n) begin
271	            current_pointer_wb_r <= 0;
272	        end else begin
273	            if(start_new_instruction) begin
274	                current_pointer_wb_r <= 0;
275	            end else if (start_new_loop) begin
276	                current_pointer_wb_r <= 0;
277	            end else if (current_finished) begin
278	                current_pointer_wb_r <= 0;
279	            end else if(new_transaction_en) begin
280	                current_pointer_wb_r <= nxt_elem;
281	            end
282	        end
283	    end
284	    // Create new pending states
285	    always_comb begin : get_new_elem_pending
286	        // next pending state for new instruction
287	        if(instr_in.vl < VECTOR_LANES) begin
288	            nxt_pending_elem = ~('1 << instr_in.vl);
289	        end else begin
290	            nxt_pending_elem = '1;
291	        end
292	        // next pending state for new loop
293	        if(nxt_total_remaining_elements < VECTOR_LANES) begin
294	            nxt_pending_elem_loop = ~('1 << nxt_total_remaining_elements);
295	        end else begin
296	            nxt_pending_elem_loop = '1;
297	        end
298	    end
299	    // Store new pending states
300	    assign current_served_th  = (~('1 << el_served_count)) << current_pointer_wb_r;
301	    assign current_pointer_oh = 1 << current_pointer_wb_r;
302	    always_ff @(posedge clk or negedge rst_n) begin : pending_status
303	        if(~rst_n) begin
304	            pending_elem <= '0;
305	        end else begin
306	            for (int i = 0; i < VECTOR_LANES; i++) begin
307	                if(start_new_instruction) begin
308	                    pending_elem[i] <= nxt_pending_elem[i];
309	                end else if (start_new_loop) begin
310	                    pending_elem[i] <= nxt_pending_elem_loop[i];
311	                end else if(new_transaction_en && current_served_th[i] && multi_valid) begin // multi-request
312	                    pending_elem[i] <= 1'b0;
313	                end else if(new_transaction_en && current_pointer_oh[i] && !multi_valid) begin // single-request
314	                    pending_elem[i] <= 1'b0;
315	                end
316	            end
317	        end
318	    end
319	    // Keep track of the expanions happening
320	    always_ff @(posedge clk or negedge rst_n) begin : loop_tracking
321	        if(~rst_n) begin
322	            current_exp_loop_r <= 0;
323	        end else begin
324	            if(start_new_instruction) begin
325	                current_exp_loop_r <= 0;
326	                src1_r             <= instr_in.src1;
327	                src2_r             <= instr_in.src2;
328	            end else if(start_new_loop) begin
329	                current_exp_loop_r <= current_exp_loop_r +1;
330	                src1_r             <= src1_r +1;
331	                src2_r             <= src2_r +1;
332	            end
333	        end
334	    end
335	    //Store the max expansion when reconfiguring
336	    always_ff @(posedge clk or negedge rst_n) begin : maxExp
337	        if(~rst_n) begin
338	            max_expansion_r <= 'd1;
339	        end else begin
340	            if(do_reconfigure) begin
341	                max_expansion_r <= instr_in.maxvl >> $clog2(VECTOR_LANES);
342	            end
343	        end
344	    end
345	    //=======================================================
346	    // Capture Instruction Information
347	    always_ff @(posedge clk or negedge rst_n) begin : proc_vl_r
348	        if(~rst_n) begin
349	            instr_vl_r <= VECTOR_LANES;
350	        end else begin
351	            if(start_new_instruction) begin
352	                instr_vl_r <= instr_in.vl;
353	            end
354	        end
355	    end
356	    always_ff @(posedge clk) begin
357	        if(start_new_instruction) begin
358	            microop_r          <= instr_in.microop;
359	            ticket_r           <= instr_in.ticket;
360	            last_ticket_src1_r <= instr_in.last_ticket_src1;
361	            last_ticket_src2_r <= instr_in.last_ticket_src2;
362	        end
363	    end
364	
365	    assign nxt_memory_op = instr_in.microop[`MEM_OP_RANGE_HI:`MEM_OP_RANGE_LO];
366	    always_ff @(posedge clk or negedge rst_n) begin : proc_memory_op_r
367	        if(~rst_n) begin
368	            memory_op_r <= '0;
369	        end else begin
370	            if(start_new_instruction) begin
371	                memory_op_r <= nxt_memory_op;
372	            end
373	        end
374	    end
375	
376	    // calculate start-end addresses for the op
377	    // +- 4 to avoid conflicts due to data sizes
378	    always_ff @(posedge clk or negedge rst_n) begin
379	        if(~rst_n) begin
380	            start_addr_r <= '0;
381	            end_addr_r   <= '1;
382	        end else begin
383	            if(start_new_instruction) begin
384	                start_addr_r <= nxt_base_addr;
385	                if(instr_in.microop[`MEM_OP_RANGE_HI:`MEM_OP_RANGE_LO] !== `OP_INDEXED) begin
386	                    end_addr_r <= nxt_base_addr + ((instr_in.vl -1) * nxt_stride);
387	                end else begin
388	                    end_addr_r <= nxt_base_addr; // cannot calculate end address for `OP_INDEXED ops
389	                end
390	            end
391	        end
392	    end
393	
394	
395	`ifdef MODEL_TECH
396	    `include "vmu_st_eng_sva.sv"
397	`endif
398	
399	endmodule

1	/**
2	*@info top module
3	*@info Sub-Modules: Processor_Top.sv, main_memory.sv
4	*
5	*
6	* @brief Initializes the Processor and the main memory controller, and connects them
7	*
8	*/
9	`ifdef MODEL_TECH
10	    `include "structs.sv"
11	    `include "vstructs.sv"
12	    `include "params.sv"
13	    `include "../vector_simulator/decoder_results/autogenerated_params.sv"
14	`endif
15	module vector_sim_top ();
16	
17	    logic clk;
18	    logic rst_n;
19	
20	    logic                 req_rd_l2_dcache_valid;
21	    logic                 resp_l2_dcache_valid  ;
22	    logic                 write_l2_valid        ;
23	    logic [ADDR_BITS-1:0] req_rd_l2_dcache_addr ;
24	    logic [ADDR_BITS-1:0] resp_l2_dcache_addr   ;
25	    logic [ADDR_BITS-1:0] req_wr_l2_dcache_addr ;
26	    logic [    DC_DW-1:0] req_wr_l2_dcache_data ;
27	    logic [    DC_DW-1:0] resp_l2_dcache_data   ;
28	    logic                 req_wr_l2_dcache_valid;
29	    logic                 valid_instr           ;
30	    to_vector             vector_instr          ;
31	    logic                 vector_pop            ;
32	    logic                 mem_req_valid         ;
33	    vector_mem_req        mem_req               ;
34	    logic                 cache_vector_ready    ;
35	    logic                 mem_resp_valid        ;
36	    vector_mem_resp       mem_resp              ;
37	    logic                 vector_idle           ;
38	
39	    // generate clock
40	    always
41	        begin
42	        clk = 1; #5; clk = 0; #5;
43	    end
44	
45	    // generate reset
46	    initial begin
47	        $display("Testbench Starting...");
48	        rst_n=0;
49	        @(posedge clk);
50	        rst_n=0;
51	        @(posedge clk);
52	        rst_n=1;
53	        @(posedge clk);
54	        @(posedge clk);@(posedge clk);
55	        $display("Exiting Reset...");
56	    end
57	
58	    // autofinish simulation
59	    logic [63:0] previous_total_issues ;
60	    logic [31:0] idle_counter          ;
61	    logic [31:0] deadlock_counter      ;
62	    logic        force_end_sim_empty   ;
63	    logic        force_end_sim_deadlock;
64	    logic        memory_empty          ;
65	    logic        pipeline_empty        ;
66	    logic        sim_finished          ;
67	    logic        sim_stop              ;
68	
69	    always_ff @(posedge clk or negedge rst_n) begin
70	        if(~rst_n) begin
71	            previous_total_issues <= 0;
72	        end else begin
73	            previous_total_issues <= vector_top.vis.total_issues;
74	        end
75	    end
76	
77	    assign memory_empty   = ~(vector_driver.head < SIM_VECTOR_INSTRS);
78	    assign pipeline_empty = memory_empty & ~vector_top.vis.valid_in;
79	    always_ff @(posedge clk or negedge rst_n) begin
80	        if(~rst_n) begin
81	            idle_counter <= 0;
82	        end else begin
83	            if(pipeline_empty) idle_counter <= idle_counter +1;
84	            else               idle_counter <= 0;
85	        end
86	    end
87	
88	    assign deadlock_en = valid_instr & (vector_top.vis.total_issues === previous_total_issues);
89	    always_ff @(posedge clk or negedge rst_n) begin
90	        if(~rst_n) begin
91	            deadlock_counter <= 0;
92	        end else begin
93	            if(deadlock_en) deadlock_counter <= deadlock_counter +1;
