1	`include "vstructs.sv"
2	module vector_driver #(
3	    parameter int DEPTH            = 4 ,
4	    parameter int DATA_WIDTH       = 32,
5	    parameter int VECTOR_REGISTERS = 32,
6	    parameter int VECTOR_LANES     = 8 ,
7	    parameter int MICROOP_WIDTH    = 32
8	) (
9	    input  logic     clk    ,
10	    input  logic     rst_n  ,
11	    // input side
12	    output logic     valid_o,
13	    output to_vector instr_o,
14	    input  logic     pop_i
15	);
16	
17	    logic [$clog2(DEPTH+1)-1:0] head;
18	    // Memory Initialized with the generator outputs
19	    logic                                reconfiguration_list[DEPTH-1:0];
20	    logic [              DATA_WIDTH-1:0] data1_list          [DEPTH-1:0];
21	    logic [              DATA_WIDTH-1:0] data2_list          [DEPTH-1:0];
22	    logic [              DATA_WIDTH-1:0] immediate_list      [DEPTH-1:0];
23	    logic [$clog2(VECTOR_REGISTERS)-1:0] destination_list    [DEPTH-1:0];
24	    logic [$clog2(VECTOR_REGISTERS)-1:0] operand_a_list      [DEPTH-1:0];
25	    logic [$clog2(VECTOR_REGISTERS)-1:0] operand_b_list      [DEPTH-1:0];
26	    logic [$clog2(VECTOR_REGISTERS)-1:0] operand_c_list      [DEPTH-1:0];
27	    logic [           MICROOP_WIDTH-1:0] microop_list        [DEPTH-1:0];
28	    logic [                         1:0] fu_list             [DEPTH-1:0];
29	    logic [                      32-1:0] maxvl_list          [DEPTH-1:0];
30	    logic [                      32-1:0] vl_list             [DEPTH-1:0];
31	
32	    // Load the Memories
33	    initial begin
34	        $readmemb("../vector_simulator/decoder_results/instrs/data1_output.txt",data1_list);
35	        $readmemb("../vector_simulator/decoder_results/instrs/data2_output.txt",data2_list);
36	        $readmemb("../vector_simulator/decoder_results/instrs/immediate_output.txt",immediate_list);
37	        $readmemb("../vector_simulator/decoder_results/instrs/destination_output.txt",destination_list);
38	        $readmemb("../vector_simulator/decoder_results/instrs/operand_a_output.txt",operand_a_list);
39	        $readmemb("../vector_simulator/decoder_results/instrs/operand_b_output.txt",operand_b_list);
40	        $readmemb("../vector_simulator/decoder_results/instrs/operand_c_output.txt",operand_c_list);
41	        $readmemb("../vector_simulator/decoder_results/instrs/microop_output.txt",microop_list);
42	        $readmemb("../vector_simulator/decoder_results/instrs/fu_output.txt",fu_list);
43	        $readmemb("../vector_simulator/decoder_results/instrs/reconfigure_output.txt",reconfiguration_list);
44	        $readmemb("../vector_simulator/decoder_results/instrs/maxvl_output.txt",maxvl_list);
45	        $readmemb("../vector_simulator/decoder_results/instrs/vl_output.txt",vl_list);
46	    end
47	
48	    logic instr_is_dummy;
49	    // A dummy instruction is a NOP that will be poped from the list but not issued
50	    // Used to emulate cycles where the scalar core decodes scalar instructions (e.g. control instrs)
51	    assign instr_is_dummy = reconfiguration_list[head] & &fu_list[head] & microop_list[head] & ~|vl_list[head] & ~|maxvl_list[head];
52	
53	    // Manage the list head pointer
54	    always_ff @(posedge clk or negedge rst_n) begin
55	        if(~rst_n) begin
56	            head <= 0;
57	        end else begin
58	            if (pop_i | instr_is_dummy) head <= head +1;
59	        end
60	    end
61	
62	    // Create the Outputs
63	    assign valid_o = (head < DEPTH) & rst_n & ~instr_is_dummy;
64	
65	    assign instr_o.valid       = valid_o;
66	    assign instr_o.dst         = destination_list[head];
67	    assign instr_o.src1        = operand_a_list[head];
68	    assign instr_o.src2        = operand_b_list[head];
69	    assign instr_o.data1       = data1_list[head];
70	    assign instr_o.data2       = data2_list[head];
71	    assign instr_o.reconfigure = reconfiguration_list[head];
72	    assign instr_o.immediate   = immediate_list[head];
73	    assign instr_o.fu          = fu_list[head];
74	    assign instr_o.microop     = microop_list[head];
75	    assign instr_o.maxvl       = maxvl_list[head][$clog2(VECTOR_REGISTERS*VECTOR_LANES):0];
76	    assign instr_o.vl          = vl_list[head][$clog2(VECTOR_REGISTERS*VECTOR_LANES):0];
77	    assign instr_o.use_mask    = '0;
78	
79	endmodule
