541	//=======================================================
542	    logic stall_row_0_while_ready, stall_row_1_while_ready;
543	    logic [63:0] total_tp_stalled_due_is;
544	
545	    assign stall_row_0_while_ready = ~|(active_elem[0] ^ served_elem[0]) & |active_elem[0] & (~wrtbck_locked_a_i | wrtbck_ticket_a_i !== ticket_r);
546	    assign stall_row_1_while_ready = ~|(active_elem[1] ^ served_elem[1]) & |active_elem[1] & (~wrtbck_locked_b_i | wrtbck_ticket_b_i !== ticket_r);
547	
548	    always_ff @(posedge clk or negedge rst_n) begin
549	        if(~rst_n) begin
550	            total_tp_stalled_due_is <= 0;
551	        end else begin
552	            if (stall_row_0_while_ready | stall_row_1_while_ready)
553	                total_tp_stalled_due_is <= total_tp_stalled_due_is +1;
554	        end
555	    end
